#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MOD 1000000007

int countSemiPalindromic(int S, long long K) {
    int count = 0;
    for (long long i = 0; i < (long long) pow(10, K); i++) {
        char str[100];
        sprintf(str, "%lld", i);
        int len = strlen(str);
        int freq[10] = {0};
        for (int j = 0; j < len; j++) {
            freq[str[j] - '0']++;
        }
        int oddCount = 0;
        for (int j = 0; j < 10; j++) {
            if (freq[j] % 2 != 0) {
                oddCount++;
            }
        }
        if (oddCount > 1) {
            continue;
        }
        if (i % S == 0) {
            count++;
        }
    }
    return count % MOD;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int S;
        long long K;
        scanf("%d %lld", &S, &K);
        printf("%d\n", countSemiPalindromic(S, K));
    }
    return 0;
}

